mapper.select:
SELECT R.RVW_NO AS rvwNo, R.RVW_PLC_NO AS rvwPlcNo, R.RVW_RATING AS rvwRating, R.RVW_CONTENT AS rvwContent, DATE_FORMAT(R.RVW_REG_DATE, '%Y-%m-%d') AS rvwRegDate, R.RVW_USE_YN AS rvwUseYn, M.MBR_NICKNAME AS nickname, P.PLC_NAME AS plcName FROM REVIEW R JOIN MEMBER M ON R.RVW_MBR_ID = M.MBR_ID JOIN PLACE P ON R.RVW_PLC_NO = P.PLC_NO
R.RVW_USE_YN = 'N' 1=1 R.RVW_USE_YN = 'Y'
ORDER BY R.RVW_NO DESC LIMIT #{offset}, #{size}

mapper.update:
UPDATE PLACE
SET
  PLC_AVG_RATING = (
    SELECT COALESCE(ROUND(AVG(RVW_RATING), 1), 0.0)
    FROM REVIEW
    WHERE RVW_PLC_NO = #{plcNo}
      AND RVW_USE_YN = 'Y'
  ),
  PLC_REVIEW_CNT = (
    SELECT COUNT(*)
    FROM REVIEW
    WHERE RVW_PLC_NO = #{plcNo}
      AND RVW_USE_YN = 'Y'
  ),
  PLC_UP_DATE = NOW()
WHERE PLC_NO = #{plcNo}
